@app.route('/assignments/submit/<assignment_id>', methods=['GET', 'POST'])
def submit_assignment(assignment_id):
    username = LOGGED_IN_USERNAME
    assignments = load_assignments()
    assignment = next((a for a in assignments if a['assignment_id'] == assignment_id), None)
    if not assignment:
        abort(404)

    submissions = load_submissions()
    submission = next((s for s in submissions if s['assignment_id'] == assignment_id and s['username'] == username), None)

    if request.method == 'POST':
        submission_text = request.form.get('submission_text', '').strip()
        if not submission_text:
            # Missing submission text, re-render with error
            error = 'Submission text is required.'
            return render_template('submit_assignment.html', assignment=assignment, submission_text=submission_text, error=error)

        submit_date = datetime.now().strftime('%Y-%m-%d')

        if submission:
            # Update existing submission
            submission['submission_text'] = submission_text
            submission['submit_date'] = submit_date
            submission['grade'] = None
            submission['feedback'] = None
        else:
            # Add new submission
            new_id = generate_new_submission_id(submissions)
            new_submission = {
                'submission_id': new_id,
                'assignment_id': assignment_id,
                'username': username,
                'submission_text': submission_text,
                'submit_date': submit_date,
                'grade': None,
                'feedback': None
            }
            submissions.append(new_submission)

        save_submissions(submissions)
        return redirect(url_for('assignments'))

    # GET
    submission_text = submission['submission_text'] if submission else None
    return render_template('submit_assignment.html', assignment=assignment, submission_text=submission_text)


